// ── Helpers ──────────────────────────────────────────────────────────────────

function pct(numerator: number, denominator: number): number | null {
  if (!denominator) return null;
  return (numerator / denominator) * 100;
}

function statRow(label: string, value: string | null, note?: string) {
  return (
    <div className="flex justify-between items-start py-2 border-b border-gray-100 last:border-0">
      <div>
        <span className="text-sm text-gray-700">{label}</span>
        {note && <p className="text-xs text-gray-500 mt-0.5">{note}</p>}
      </div>
      <span className="text-sm font-semibold text-[#1A4A6B] ml-4 shrink-0">
        {value ?? 'N/A'}
      </span>
    </div>
  );
}

// Color scale for disability rates: green (low) → yellow → red (high)
function rateColor(rate: number): string {
  if (rate < 10) return 'text-green-700 bg-green-50';
  if (rate < 18) return 'text-yellow-700 bg-yellow-50';
  return 'text-red-700 bg-red-50';
}

// ── SORTA paratransit helpers ─────────────────────────────────────────────────

interface SORTAStop {
  stop_lat: number;
  stop_lon: number;
  stop_name: string;
  routes: string[];
}

async function loadSORTAStops(): Promise<SORTAStop[]> {
  const resp = await fetch('/data/sorta_stops.json');
  if (!resp.ok) throw new Error('SORTA stops unavailable');
  return resp.json();
}

// ── Sub-components ────────────────────────────────────────────────────────────

/** Big stat callout used in each view's key metrics section */
function StatCallout({
  value,
  label,
  sub,
  colorClass,
}: {
  value: string;
  label: string;
  sub?: string;
  colorClass?: string;
}) {
  return (
    <div className={`rounded-lg p-4 text-center ${colorClass ?? 'bg-blue-50'}`}>
      <div className={`text-3xl font-bold ${colorClass ? '' : 'text-[#1A4A6B]'}`}>{value}</div>
      <div className="text-sm font-medium mt-1">{label}</div>
      {sub && <div className="text-xs text-gray-500 mt-0.5">{sub}</div>}
    </div>
  );
}

/**
 * Paratransit coverage card — computes ADA Access coverage from SORTA stops.
 * The ADA requires complementary paratransit within 3/4 mile of any fixed route.
 */
function ParatransitCard({ neighborhood }: { neighborhood: string }) {
  const [stopsNearby, setStopsNearby] = useState<number | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const centroid = NEIGHBORHOOD_CENTROIDS[neighborhood];

  useEffect(() => {
    if (!centroid) {
      setError('No centroid data for this neighborhood.');
      setLoading(false);
      return;
    }
    setLoading(true);
    setError(null);
    loadSORTAStops()
      .then((stops) => {
        const [lat, lon] = centroid;
        const nearby = stops.filter(
          (s) => distanceMiles(lat, lon, s.stop_lat, s.stop_lon) <= ADA_PARATRANSIT_RADIUS_MILES
        ).length;
        setStopsNearby(nearby);
      })
      .catch((e) => setError(String(e)))
      .finally(() => setLoading(false));
  }, [neighborhood, centroid]);

  const covered = stopsNearby !== null && stopsNearby > 0;

  return (
    <DataCard
      title="ADA Paratransit Coverage (SORTA Access)"
      loading={loading}
      error={error}
      attribution={{ datasetName: 'SORTA GTFS Static Feed', lastUpdated: null, url: 'https://www.go-metro.com/about/developer-data/' }}
    >
      <div className="space-y-3">
        {/* Coverage status */}
        <div className={`flex items-center gap-3 p-3 rounded-lg ${covered ? 'bg-green-50' : 'bg-red-50'}`}>
          <span className="text-2xl">{covered ? '✅' : '⚠️'}</span>
          <div>
            <p className={`font-semibold text-sm ${covered ? 'text-green-800' : 'text-red-800'}`}>
              {covered
                ? `SORTA Access paratransit is available here`
                : `Paratransit coverage is uncertain for this neighborhood`}
            </p>
            <p className="text-xs text-gray-600 mt-0.5">
              {stopsNearby !== null
                ? `${stopsNearby} fixed-route bus stop${stopsNearby !== 1 ? 's' : ''} within ¾ mile of neighborhood center`
                : 'Loading…'}
            </p>
          </div>
        </div>

        {/* How this works */}
        <div className="text-sm text-gray-700 space-y-1.5">
          <p>
            Under the <strong>Americans with Disabilities Act (ADA)</strong>, transit agencies must
            offer paratransit service within <strong>¾ mile</strong> of every fixed-route bus line,
            during the same hours. SORTA's service is called <strong>Access</strong>.
          </p>
          <p>
            This calculation uses the neighborhood's geographic center. Individual addresses near
            the neighborhood boundary may have different coverage — use{' '}
            <a
              href="https://www.go-metro.com/riding-metro/accessibility/access"
              target="_blank"
              rel="noopener noreferrer"
              className="text-[#1A4A6B] underline"
            >
              SORTA's Access eligibility tool
            </a>{' '}
            to check a specific address.
          </p>
        </div>

        {/* Data gap callout */}
        <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 text-xs text-amber-800 space-y-1">
          <p className="font-semibold">📊 Data we don't have yet</p>
          <p>
            SORTA's GTFS feed includes a <code>wheelchair_boarding</code> field indicating which
            stops have accessible boarding. Our current stops file was built without it — this
            score currently reflects stop proximity only, not confirmed accessibility at each stop.
          </p>
          <p>
            <a
              href="https://www.go-metro.com/about/developer-data/"
              target="_blank"
              rel="noopener noreferrer"
              className="underline font-medium"
            >
              View SORTA's open developer data →
            </a>
          </p>
        </div>
      </div>
    </DataCard>
  );
}

