// ── Main component ────────────────────────────────────────────────────────────

export default function Accessibility() {
  useTranslation(); // keep i18n context available for future string keys
  const [selectedNeighborhood, setSelectedNeighborhood] = useState<string>(NEIGHBORHOODS[0]);
  const [activeView, setActiveView] = useState<ImpairmentView>('overview');
  const [disabilityMap, setDisabilityMap] = useState<Map<string, NeighborhoodDisabilityStats>>(new Map());
  const [loadingStats, setLoadingStats] = useState(true);
  const [statsError, setStatsError] = useState<string | null>(null);

  // Load disability stats once on mount
  useEffect(() => {
    setLoadingStats(true);
    fetchNeighborhoodDisabilityStats()
      .then(setDisabilityMap)
      .catch((e) => setStatsError(String(e)))
      .finally(() => setLoadingStats(false));
  }, []);

  const stats = useMemo((): NeighborhoodDisabilityStats | null => {
    if (loadingStats || disabilityMap.size === 0) return null;
    const key = stripNeighborhoodName(selectedNeighborhood);
    return disabilityMap.get(key) ?? null;
  }, [disabilityMap, selectedNeighborhood, loadingStats]);

  return (
    <div className="space-y-6">
      {/* Page header */}
      <div>
        <h1 className="text-2xl font-bold text-[#1A4A6B]">♿ Accessibility Resource Center</h1>
        <p className="text-gray-600 mt-1 text-sm">
          Disability demographics, transit coverage, and infrastructure data for Cincinnati neighborhoods.
          Use the impairment type selector to focus on what matters to you.
        </p>
      </div>

      {/* Controls: neighborhood + view selector */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-4 space-y-4">
        {/* Neighborhood selector */}
        <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center">
          <label htmlFor="acc-neighborhood" className="text-sm font-medium text-gray-700 shrink-0">
            Neighborhood
          </label>
          <select
            id="acc-neighborhood"
            value={selectedNeighborhood}
            onChange={(e) => setSelectedNeighborhood(e.target.value)}
            className="w-full sm:w-auto border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-[#1A4A6B] bg-white"
          >
            {NEIGHBORHOODS.map((n) => (
              <option key={n} value={n}>{n}</option>
            ))}
          </select>
          {loadingStats && (
            <span className="text-xs text-gray-500 animate-pulse">Loading disability data…</span>
          )}
          {statsError && (
            <span className="text-xs text-red-500">{statsError}</span>
          )}
        </div>

        {/* Impairment view pills */}
        <div>
          <p className="text-xs font-medium text-gray-500 mb-2">View by impairment type</p>
          <div className="flex flex-wrap gap-2">
            {VIEWS.map((view) => (
              <button
                key={view.id}
                onClick={() => setActiveView(view.id)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-colors border ${
                  activeView === view.id
                    ? 'bg-[#1A4A6B] text-white border-[#1A4A6B]'
                    : 'bg-white text-gray-700 border-gray-300 hover:border-[#1A4A6B] hover:text-[#1A4A6B]'
                }`}
                title={view.description}
              >
                <span>{view.icon}</span>
                <span>{view.label}</span>
              </button>
            ))}
          </div>
          <p className="text-xs text-gray-500 mt-2 italic">
            {VIEWS.find((v) => v.id === activeView)?.description}
          </p>
        </div>
      </div>

      {/* Active view content */}
      <div>
        {activeView === 'overview' && (
          <OverviewView stats={stats} neighborhood={selectedNeighborhood} />
        )}
        {activeView === 'mobility' && (
          <MobilityView stats={stats} neighborhood={selectedNeighborhood} />
        )}
        {activeView === 'vision' && (
          <VisionView stats={stats} />
        )}
        {activeView === 'hearing' && (
          <HearingView stats={stats} />
        )}
        {activeView === 'cognitive' && (
          <CognitiveView stats={stats} />
        )}
      </div>

      {/* Data gaps call to action — always shown at bottom */}
      <DataGapsCard view={activeView} />

      {/* ACS data note */}
      <div className="text-xs text-gray-500 bg-gray-50 rounded-lg p-3 space-y-1">
        <p className="font-medium text-gray-600">About this data</p>
        <p>
          Disability statistics are from the <strong>U.S. Census American Community Survey
          5-Year estimates (2022)</strong>, table series B18101–B18107 and C18130.
          ACS data is survey-based — estimates for small neighborhoods carry wider margins of error.
          Neighborhood boundaries use Cincinnati's Statistical Neighborhood Approximations (SNAs);
          census tract boundaries don't align perfectly and some ambiguous tracts are attributed
          to their nearest neighborhood centroid.
        </p>
        <p>
          <a
            href="https://www.census.gov/programs-surveys/acs/data.html"
            target="_blank"
            rel="noopener noreferrer"
            className="text-[#1A4A6B] underline"
          >
            U.S. Census ACS →
          </a>
          {' · '}
          <a
            href="https://censusreporter.org/tables/B18101/"
            target="_blank"
            rel="noopener noreferrer"
            className="text-[#1A4A6B] underline"
          >
            Explore disability tables on Census Reporter →
          </a>
        </p>
      </div>
    </div>
  );
}
